pure fn mean(nums: Number) -> Number {
    total = 0
    for n in nums { total = total + n }
    return total / length(nums)
}

pure fn variance(nums: Number) -> Number {
    avg = mean(nums)
    total = 0
    for n in nums { total = total + (n - avg) * (n - avg) }
    return total / length(nums)
}

pure fn std_dev(nums: Number) -> Number {
    return sqrt(variance(nums))
}

entry main(x: Text) {
