def parse_coords(text):
    return [(c.split(':')[0], float(c.split(':')[1])) for c in text.split(',')]

def sort_by_lat(coords):
    return sorted(coords, key=lambda x: x[1])

def describe_pattern(coords):
    if coords[0][1] < coords[-1][1]:
        return 'Northern Hemisphere'
    elif coords[0][1] > coords[-1][1]:
        return 'Southern Hemisphere'
    else:
        return 'Equator'

text = 'Tokyo:35.6,London:51.5,Sydney:-33.8'
coords = parse_coords(text)
sorted_coords = sort_by_lat(coords)
pattern = describe_pattern(sorted_coords)

print(pattern)

